// SSE event stream route
import { Hono } from "hono";
import { eventBus, type EventName } from "../../koina/event-bus.js";
import type { RouteDeps, RouteRefs } from "./deps.js";

export function eventRoutes(deps: RouteDeps, _refs: RouteRefs): Hono {
  const app = new Hono();
  const { manager } = deps;

  app.get("/api/events", (c) => {
    const encoder = new TextEncoder();
    let closed = false;
    const deliveryQueue = deps.deliveryQueue;

    const stream = new ReadableStream({
      start(controller) {
        const activeTurns = manager.getActiveTurnDetails();
        const pendingCount = deliveryQueue?.size ?? 0;
        controller.enqueue(encoder.encode(`event: init\ndata: ${JSON.stringify({ activeTurns, pendingDeliveries: pendingCount })}\n\n`));

        // Flush any pending deliveries from disconnected sessions
        if (deliveryQueue) {
          // Check all agents for pending deliveries
          const nousIds = new Set(activeTurns.map(t => t.nousId));
          // Also check configured agents
          for (const agent of deps.config.agents.list) {
            nousIds.add(agent.id);
          }
          for (const nousId of nousIds) {
            const pending = deliveryQueue.flushByNous(nousId);
            for (const delivery of pending) {
              try {
                controller.enqueue(encoder.encode(
                  `event: missed_delivery\ndata: ${JSON.stringify({
                    type: "missed_delivery",
                    sessionId: delivery.sessionId,
                    nousId: delivery.nousId,
                    turnId: delivery.turnId,
                    payload: delivery.payload,
                    queuedAt: delivery.createdAt,
                    attempts: delivery.attempts,
                  })}\n\n`,
                ));
              } catch { closed = true; }
            }
          }
        }

        const forward = (eventName: string) => (data: unknown) => {
          if (closed) return;
          try {
            controller.enqueue(encoder.encode(`event: ${eventName}\ndata: ${JSON.stringify(data)}\n\n`));
          } catch { closed = true; }
        };

        const handlers: Array<[EventName, (data: unknown) => void]> = [
          ["turn:before", forward("turn:before")],
          ["turn:after", forward("turn:after")],
          ["tool:called", forward("tool:called")],
          ["tool:failed", forward("tool:failed")],
          ["status:update", forward("status:update")],
          ["session:created", forward("session:created")],
          ["session:archived", forward("session:archived")],
          ["distill:before", forward("distill:before")],
          ["distill:stage", forward("distill:stage")],
          ["distill:after", forward("distill:after")],
          ["planning:project-created", forward("planning:project-created")],
          ["planning:project-resumed", forward("planning:project-resumed")],
          ["planning:phase-started", forward("planning:phase-started")],
          ["planning:phase-complete", forward("planning:phase-complete")],
          ["planning:checkpoint", forward("planning:checkpoint")],
          ["planning:complete", forward("planning:complete")],
          ["planning:requirement-changed", forward("planning:requirement-changed")],
          ["planning:phase-changed", forward("planning:phase-changed")],
          ["planning:discussion-answered", forward("planning:discussion-answered")],
          ["planning:annotation-changed", forward("planning:annotation-changed")],
          ["planning:edit-recorded", forward("planning:edit-recorded")],
          ["task:created", forward("task:created")],
          ["task:updated", forward("task:updated")],
          ["task:completed", forward("task:completed")],
          ["task:deleted", forward("task:deleted")],
          ["task:bulk-created", forward("task:bulk-created")],
        ];

        for (const [event, handler] of handlers) {
          eventBus.on(event, handler);
        }

        // Send keepalive as a named event (not a comment) so the browser's
        // EventSource actually delivers it to listeners. SSE comments (": ping")
        // are silently consumed by the parser and never fire onmessage or
        // addEventListener — making them invisible to client heartbeat detection.
        const pingInterval = setInterval(() => {
          if (closed) return;
          try { controller.enqueue(encoder.encode(`event: ping\ndata: {}\n\n`)); }
          catch { closed = true; }
        }, 15_000);

        c.req.raw.signal.addEventListener("abort", () => {
          closed = true;
          clearInterval(pingInterval);
          for (const [event, handler] of handlers) {
            eventBus.off(event, handler);
          }
          try { controller.close(); } catch { /* already closed */ }
        });
      },
    });

    return new Response(stream, {
      headers: {
        "Content-Type": "text/event-stream",
        "Cache-Control": "no-cache",
        "Connection": "keep-alive",
        "X-Accel-Buffering": "no",
      },
    });
  });

  return app;
}
