// Config inspection tool — agents can read their own scoped config
import type { ToolContext, ToolHandler } from "../registry.js";
import type { AletheiaConfig } from "../../taxis/schema.js";
import { resolveNous } from "../../taxis/loader.js";

export function createConfigReadTool(config?: AletheiaConfig): ToolHandler {
  return {
    definition: {
      name: "config_read",
      description:
        "Read your own agent config, system bindings, cron jobs, or gateway info.\n\n" +
        "USE WHEN:\n" +
        "- Checking your own model, tools, or workspace configuration\n" +
        "- Listing available agents and their IDs\n" +
        "- Reviewing cron schedules or plugin status\n\n" +
        "DO NOT USE WHEN:\n" +
        "- You need session-level info — use session_status instead\n\n" +
        "TIPS:\n" +
        "- Sections: agent, agents, bindings, cron, gateway, plugins\n" +
        "- 'agent' shows YOUR config; 'agents' lists all agent IDs\n" +
        "- Bindings are filtered to your agent only",
      input_schema: {
        type: "object",
        properties: {
          section: {
            type: "string",
            description:
              "Config section: 'agent' (your config), 'agents' (all agent IDs), 'bindings', 'cron', 'gateway', 'plugins'",
          },
        },
        required: ["section"],
      },
    },
    execute(
      input: Record<string, unknown>,
      context: ToolContext,
    ): Promise<string> {
      const section = input["section"] as string;

      if (!config) {
        return Promise.resolve(JSON.stringify({ error: "Config not available" }));
      }

      switch (section) {
        case "agent": {
          const nous = resolveNous(config, context.nousId);
          if (!nous) return Promise.resolve(JSON.stringify({ error: `Unknown nous: ${context.nousId}` }));
          return Promise.resolve(JSON.stringify({
            id: nous.id,
            name: nous.name,
            workspace: nous.workspace,
            model: nous.model ?? config.agents.defaults.model,
            tools: nous.tools,
            heartbeat: nous.heartbeat,
          }));
        }
        case "agents":
          return Promise.resolve(JSON.stringify(
            config.agents.list.map((a) => ({
              id: a.id,
              name: a.name ?? a.id,
            })),
          ));
        case "bindings":
          return Promise.resolve(JSON.stringify(
            config.bindings.filter((b) => b.agentId === context.nousId),
          ));
        case "cron":
          return Promise.resolve(JSON.stringify(
            config.cron.jobs.filter(
              (j) => !j.agentId || j.agentId === context.nousId,
            ),
          ));
        case "gateway":
          return Promise.resolve(JSON.stringify({
            port: config.gateway.port,
            bind: config.gateway.bind,
          }));
        case "plugins":
          return Promise.resolve(JSON.stringify({
            enabled: config.plugins.enabled,
            count: Object.keys(config.plugins.entries).length,
            plugins: Object.entries(config.plugins.entries).map(
              ([id, p]) => ({ id, enabled: p.enabled }),
            ),
          }));
        default:
          return Promise.resolve(JSON.stringify({ error: `Unknown section: ${section}` }));
      }
    },
  };
}

export const configReadTool = createConfigReadTool();
