// Distillation pipeline — multi-pass context compression with hardening
import { createLogger } from "../koina/logger.js";
import { AletheiaError } from "../koina/errors.js";
import { estimateTokens } from "../hermeneus/token-counter.js";
import type { ProviderRouter } from "../hermeneus/router.js";
import type { SessionStore } from "../mneme/store.js";
import { extractFromMessages } from "./extract.js";
import { summarizeMessages } from "./summarize.js";
import { type FlushOptions, flushToMemory, type MemoryFlushTarget } from "./hooks.js";
import { detectCrossChunkContradictions } from "./contradiction-detect.js";
import { sanitizeToolResults, summarizeInStages } from "./chunked-summarize.js";
import { pruneBySimilarity } from "./similarity-pruning.js";
import type { PluginRegistry } from "../prostheke/registry.js";
import { eventBus } from "../koina/event-bus.js";
import { flushToWorkspaceWithRetry } from "./workspace-flush.js";

const log = createLogger("melete");

const workspaceFlushFailures = new Map<string, number>();
const WORKSPACE_FLUSH_FAILURE_THRESHOLD = 3;

const activeDistillations = new Map<string, AbortController>();

export function cancelDistillation(sessionId: string): boolean {
  const controller = activeDistillations.get(sessionId);
  if (!controller) return false;
  controller.abort();
  return true;
}

async function invalidateContradictedFacts(
  contradictions: string[],
  sidecarUrl: string,
  agentId: string,
): Promise<void> {
  for (const contradiction of contradictions) {
    try {
      const res = await fetch(`${sidecarUrl}/temporal/facts/invalidate_text`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ text: contradiction, user_id: agentId, reason: "contradiction_detected" }),
        signal: AbortSignal.timeout(10_000),
      });
      if (!res.ok) {
        log.warn(`Contradiction invalidation failed (${res.status}): ${contradiction.slice(0, 80)}`);
      }
    } catch (error) {
      log.warn(`Contradiction invalidation error: ${error instanceof Error ? error.message : error}`);
      // Non-fatal — contradiction invalidation should never block distillation
    }
  }
}

export interface DistillationOpts {
  triggerThreshold: number;
  minMessages: number;
  extractionModel: string;
  summaryModel: string;
  memoryTarget?: MemoryFlushTarget;
  plugins?: PluginRegistry;
  preserveRecentMessages?: number;
  preserveRecentMaxTokens?: number;
  workspace?: string;
  /** Skip extraction and use single-sentence summary for background sessions. */
  lightweight?: boolean;
  /** PII config for memory flush redaction. */
  piiConfig?: FlushOptions["piiConfig"];
  /** Called after successful distillation to update the thread-level running summary. */
  onThreadSummaryUpdate?: (summary: string, keyFacts: string[]) => void;
  /** Sidecar base URL for contradiction invalidation (e.g. http://127.0.0.1:8230). */
  sidecarUrl?: string;
  /** True when triggered by context overflow (90% ceiling). */
  emergency?: boolean;
  /** AbortSignal to cancel an in-progress distillation. Cancel = full rollback. */
  signal?: AbortSignal;
}

export interface DistillationResult {
  sessionId: string;
  nousId: string;
  messagesBefore: number;
  messagesAfter: number;
  tokensBefore: number;
  tokensAfter: number;
  factsExtracted: number;
  summary: string;
  distillationNumber: number;
}

export function shouldDistill(
  store: SessionStore,
  sessionId: string,
  opts: { threshold: number; minMessages: number },
): boolean {
  const session = store.findSessionById(sessionId);
  if (!session) return false;

  if (session.messageCount < opts.minMessages) return false;

  return session.tokenCountEstimate >= opts.threshold;
}

export async function distillSession(
  store: SessionStore,
  router: ProviderRouter,
  sessionId: string,
  nousId: string,
  opts: DistillationOpts,
): Promise<DistillationResult> {
  // Check if already aborted before doing any work
  opts.signal?.throwIfAborted();

  const controller = new AbortController();
  activeDistillations.set(sessionId, controller);

  // Link external signal to internal controller
  if (opts.signal) {
    opts.signal.addEventListener("abort", () => controller.abort(opts.signal?.reason), { once: true });
  }

  const mergedOpts: DistillationOpts = { ...opts, signal: controller.signal };

  if (!store.acquireDistillationLock(sessionId, nousId)) {
    activeDistillations.delete(sessionId);
    log.info(
      `Distillation already in progress for session ${sessionId}, skipping`,
    );
    throw new AletheiaError({
      code: "SESSION_LOCKED", module: "melete",
      message: `Distillation already in progress for session ${sessionId}`,
      context: { sessionId }, recoverable: true, retryAfterMs: 30_000,
    });
  }

  try {
    return await runDistillation(store, router, sessionId, nousId, mergedOpts);
  } finally {
    store.releaseDistillationLock(sessionId);
    activeDistillations.delete(sessionId);
  }
}

async function runDistillation(
  store: SessionStore,
  router: ProviderRouter,
  sessionId: string,
  nousId: string,
  opts: DistillationOpts,
): Promise<DistillationResult> {
  const distillationNumber = store.incrementDistillationCount(sessionId);
  eventBus.emit("distill:before", { sessionId, nousId, distillationNumber, ...(opts.emergency ? { emergency: true } : {}) });
  log.info(
    `Starting distillation #${distillationNumber} for session ${sessionId}`,
  );

  if (distillationNumber > 3) {
    log.warn(
      `Session ${sessionId} has been distilled ${distillationNumber} times — consider archiving`,
    );
  }

  const allMessages = store.getHistory(sessionId, {});

  // Guard: reject distillation if history has orphaned tool_use blocks
  const lastAssistant = [...allMessages].toReversed().find(m => !m.isDistilled && m.role === "assistant");
  if (lastAssistant) {
    try {
      const parsed = JSON.parse(lastAssistant.content);
      if (Array.isArray(parsed)) {
        const toolUses = parsed.filter((b: { type: string }) => b.type === "tool_use");
        if (toolUses.length > 0) {
          const answeredIds = new Set(
            allMessages
              .filter(m => m.role === "tool_result" && m.seq > lastAssistant.seq)
              .map(m => m.toolCallId)
              .filter(Boolean),
          );
          const unanswered = toolUses.filter((b: { id: string }) => !answeredIds.has(b.id));
          if (unanswered.length > 0) {
            log.warn(`Distillation blocked: ${unanswered.length} unanswered tool_use blocks at seq ${lastAssistant.seq}`);
            throw new AletheiaError({
              code: "DISTILL_INSUFFICIENT_MESSAGES", module: "melete",
              message: `Cannot distill: incomplete message sequence (${unanswered.length} orphaned tool_use blocks)`,
              context: { sessionId, orphanedCount: unanswered.length },
            });
          }
        }
      }
    } catch (error) {
      if (error instanceof AletheiaError) throw error;
      log.warn(`Unexpected error during distillation pre-check: ${error instanceof Error ? error.message : error}`);
    }
  }

  const undistilled = allMessages.filter((m) => !m.isDistilled);

  if (undistilled.length < opts.minMessages) {
    throw new AletheiaError({
      code: "DISTILL_INSUFFICIENT_MESSAGES", module: "melete",
      message: `Not enough messages to distill: ${undistilled.length} < ${opts.minMessages}`,
      context: { sessionId, undistilledCount: undistilled.length, minMessages: opts.minMessages },
    });
  }

  // Check signal before any LLM work begins
  opts.signal?.throwIfAborted();

  // Split into messages to distill vs recent messages to preserve as raw context
  const preserveCount = opts.preserveRecentMessages ?? 0;
  const preserveMaxTokens = opts.preserveRecentMaxTokens ?? 4000;
  let toPreserve: typeof undistilled = [];
  let toDistill = undistilled;

  if (preserveCount > 0 && undistilled.length > preserveCount + opts.minMessages) {
    let preserveTokens = 0;
    const candidates = undistilled.slice(-preserveCount);
    for (let i = candidates.length - 1; i >= 0; i--) {
      if (preserveTokens + (candidates[i]!.tokenEstimate ?? 0) > preserveMaxTokens) break;
      preserveTokens += candidates[i]!.tokenEstimate ?? 0;
      toPreserve.unshift(candidates[i]!);
    }
    if (undistilled.length - toPreserve.length >= opts.minMessages) {
      toDistill = undistilled.slice(0, undistilled.length - toPreserve.length);
    } else {
      toPreserve = [];
    }
  }

  if (toPreserve.length > 0) {
    log.info(`Preserving ${toPreserve.length} recent messages alongside summary`);
  }

  const tokensBefore = undistilled.reduce(
    (sum, m) => sum + (m.tokenEstimate ?? 0),
    0,
  );

  if (opts.plugins) {
    await opts.plugins.dispatchBeforeDistill({
      nousId,
      sessionId,
      messageCount: undistilled.length,
      tokenCount: tokensBefore,
    });
  }

  // Build simple messages from toDistill (preserved messages stay as raw context)
  const rawMessages = toDistill
    .filter(
      (m) =>
        m.role === "user" || m.role === "assistant" || m.role === "tool_result",
    )
    .map((m) => {
      if (m.role === "tool_result") {
        const label = m.toolName ? `[tool:${m.toolName}]` : "[tool_result]";
        return { role: "user" as const, content: `${label} ${m.content}` };
      }
      return { role: m.role, content: m.content };
    });

  eventBus.emit("distill:stage", { sessionId, nousId, stage: "sanitize", progress: 1, total: 6 });

  // Sanitize tool results — truncate verbose payloads before LLM-facing operations
  const sanitized = sanitizeToolResults(rawMessages);

  // Prune low-information segments using word-overlap similarity
  const { prunedMessages: simpleMessages, removedCount: pruneCount } = pruneBySimilarity(sanitized);
  if (pruneCount > 0) log.info(`Pruned ${pruneCount} low-information messages before distillation`);

  // Lightweight mode: skip extraction + memory flush, use simple summary
  const emptyExtraction = {
    facts: [] as string[],
    decisions: [] as string[],
    openItems: [] as string[],
    keyEntities: [] as string[],
    contradictions: [] as string[],
  };
  let extraction = emptyExtraction;
  let summary: string;
  let summaryTokens: number;

  if (opts.lightweight) {
    log.info(`Lightweight distillation: ${simpleMessages.length} messages — skipping extraction`);
    const condensed = simpleMessages
      .slice(-30)
      .map((m) => `${m.role}: ${m.content.slice(0, 200)}`)
      .join("\n");
    const result = await router.complete({
      model: opts.summaryModel,
      system: "Summarize this background session in 2-3 sentences. Focus on what happened and any state that matters.",
      messages: [{ role: "user", content: condensed }],
      maxTokens: 256,
      temperature: 0,
      ...(opts.signal ? { signal: opts.signal } : {}),
    });
    const textBlock = result.content.find((b) => b.type === "text");
    summary = textBlock && "text" in textBlock ? textBlock.text : "Session distilled (no summary generated).";
    summaryTokens = estimateTokens(summary);
  } else {
    // Pass 1: Extraction
    eventBus.emit("distill:stage", { sessionId, nousId, stage: "extract", progress: 2, total: 6 });
    log.info(`Extraction pass: ${simpleMessages.length} messages`);
    extraction = await extractFromMessages(
      router,
      simpleMessages,
      opts.extractionModel,
      {
        ...(opts.sidecarUrl ? { sidecarUrl: opts.sidecarUrl } : {}),
        ...(opts.signal ? { signal: opts.signal } : {}),
      },
    );

    log.info(
      `Extracted: ${extraction.facts.length} facts, ${extraction.decisions.length} decisions, ` +
        `${extraction.openItems.length} open items, ${extraction.contradictions.length} contradictions`,
    );

    // Check signal after extraction — before summarization
    opts.signal?.throwIfAborted();

    // Cross-chunk contradiction detection — only for extractions with 2+ facts
    if (extraction.facts.length >= 2) {
      const crossChunkContradictions = await detectCrossChunkContradictions(
        router, extraction.facts, opts.extractionModel,
      );
      if (crossChunkContradictions.length > 0) {
        log.info(`Cross-chunk contradictions found: ${crossChunkContradictions.length}`);
        extraction.contradictions.push(...crossChunkContradictions);
      }
    }

    // Memory flush with retry — non-blocking, don't fail distillation on flush failure
    if (opts.memoryTarget) {
      const flushOpts: FlushOptions = {
        ...(opts.piiConfig ? { piiConfig: opts.piiConfig } : { maxRetries: 3 }),
        ...(opts.sidecarUrl ? { sidecarUrl: opts.sidecarUrl } : {}),
      };
      const flushResult = await flushToMemory(
        opts.memoryTarget,
        nousId,
        extraction,
        flushOpts,
        sessionId,
      );
      if (flushResult.errors > 0) {
        log.warn(
          `Memory flush had ${flushResult.errors} errors — some facts may be lost`,
        );
      }
    }

    // Wire contradictions to temporal invalidation — non-blocking, fire-and-forget
    if (extraction.contradictions.length > 0 && opts.sidecarUrl) {
      void invalidateContradictedFacts(extraction.contradictions, opts.sidecarUrl, nousId);
    }

    // Pass 2: Summarization — multi-stage for large conversations, single-pass for small
    eventBus.emit("distill:stage", { sessionId, nousId, stage: "summarize", progress: 3, total: 6 });
    log.info("Summary pass");
    summary = await summarizeInStages(
      router,
      simpleMessages,
      extraction,
      opts.summaryModel,
      nousId,
      opts.signal ? { signal: opts.signal } : undefined,
    );

    summaryTokens = estimateTokens(summary);

    // Compression ratio check — if summary > 50% of input, run a tighter second pass
    const compressionRatio = tokensBefore > 0 ? summaryTokens / tokensBefore : 0;
    if (compressionRatio > 0.5 && tokensBefore > 5000) {
      log.warn(
        `Compression ratio ${Math.round(compressionRatio * 100)}% exceeds 50% — running second pass`,
      );
      summary = await summarizeMessages(
        router,
        [{ role: "assistant", content: summary }],
        emptyExtraction,
        opts.summaryModel,
        nousId,
        opts.signal,
      );
      summaryTokens = estimateTokens(summary);
    }

    // Check signal after summarization — critically before SQLite mutations
    opts.signal?.throwIfAborted();
  }

  // Tag repeated distillations so agents can see compression history
  const markedSummary =
    distillationNumber > 1
      ? `[Distillation #${distillationNumber}]\n\n${summary}`
      : summary;
  const markedTokens = estimateTokens(markedSummary);

  const preservedTokens = toPreserve.reduce((sum, m) => sum + (m.tokenEstimate ?? 0), 0);

  eventBus.emit("distill:stage", { sessionId, nousId, stage: "flush", progress: 4, total: 6 });

  let flushSucceeded = true;
  let flushErrors: string | undefined;
  if (opts.workspace) {
    const flushResult = flushToWorkspaceWithRetry({
      workspace: opts.workspace,
      nousId,
      sessionId,
      distillationNumber,
      summary: markedSummary,
      extraction,
    });

    const receipt = {
      nousId,
      sessionId,
      timestamp: new Date().toISOString(),
      factCount: extraction.facts.length + extraction.decisions.length,
      written: flushResult.written,
      path: flushResult.path,
      error: flushResult.error,
    };
    log.info("Workspace flush receipt", receipt);

    if (!flushResult.written) {
      flushSucceeded = false;
      flushErrors = flushResult.error;
      const failures = (workspaceFlushFailures.get(nousId) ?? 0) + 1;
      workspaceFlushFailures.set(nousId, failures);
      if (failures >= WORKSPACE_FLUSH_FAILURE_THRESHOLD) {
        eventBus.emit("memory:health_degraded", {
          nousId,
          reason: "workspace_flush_failures",
          consecutiveFailures: failures,
          lastError: flushResult.error,
        });
      }
    } else {
      workspaceFlushFailures.delete(nousId);
    }
  }

  // Final signal check — immediately before SQLite mutations to ensure clean rollback on cancel
  opts.signal?.throwIfAborted();

  // Bundle all five SQLite writes into a single atomic transaction with single retry.
  // The transaction auto-rolls-back if any write throws, leaving no partial state.
  const mutationOpts = {
    sessionId,
    nousId,
    summaryContent: markedSummary,
    summaryTokens: markedTokens,
    distilledSeqs: toDistill.map((m) => m.seq),
    record: {
      messagesBefore: undistilled.length,
      messagesAfter: 1 + toPreserve.length,
      tokensBefore,
      tokensAfter: markedTokens + preservedTokens,
      factsExtracted: extraction.facts.length + extraction.decisions.length,
      model: opts.extractionModel,
    },
    logRecord: {
      messagesBefore: undistilled.length,
      messagesAfter: 1 + toPreserve.length,
      tokensBefore,
      tokensAfter: markedTokens + preservedTokens,
      factsExtracted: extraction.facts.length,
      decisionsExtracted: extraction.decisions.length,
      openItemsExtracted: extraction.openItems.length,
      flushSucceeded,
      ...(flushErrors ? { errors: flushErrors } : {}),
      distillationNumber,
    },
  };

  try {
    store.runDistillationMutations(mutationOpts);
  } catch (error) {
    log.warn("Distillation mutations failed (attempt 1)", { sessionId, error });
    try {
      store.runDistillationMutations(mutationOpts);
    } catch (retryError) {
      log.error("Distillation mutations failed after retry", { sessionId, error: retryError });
      // Do not rethrow — next scheduled distillation handles it
    }
  }

  const result: DistillationResult = {
    sessionId,
    nousId,
    messagesBefore: undistilled.length,
    messagesAfter: 1 + toPreserve.length,
    tokensBefore,
    tokensAfter: markedTokens + preservedTokens,
    factsExtracted: extraction.facts.length + extraction.decisions.length,
    summary: markedSummary,
    distillationNumber,
  };

  if (opts.plugins) {
    await opts.plugins.dispatchAfterDistill({
      nousId,
      sessionId,
      factsExtracted: result.factsExtracted,
      tokensBefore: result.tokensBefore,
      tokensAfter: result.tokensAfter,
    });
  }

  // Update thread-level running summary if callback provided
  if (opts.onThreadSummaryUpdate) {
    const keyFacts = [
      ...extraction.facts.slice(0, 30),
      ...extraction.decisions.map((d) => `Decision: ${d}`).slice(0, 10),
    ];
    opts.onThreadSummaryUpdate(markedSummary, keyFacts);
  }

  // Store priming data for the next turn — ensures the agent's first turn after
  // distillation has full awareness of what was just compressed, independent of
  // recall similarity matching. Consumed and cleared by context.ts on next turn.
  if (!opts.lightweight) {
    store.setDistillationPriming(sessionId, {
      facts: extraction.facts.slice(0, 20),
      decisions: extraction.decisions.slice(0, 10),
      openItems: extraction.openItems.slice(0, 10),
      summary: markedSummary.slice(0, 2000),
      distillationNumber,
      distilledAt: new Date().toISOString(),
    });
    log.info(`Stored distillation priming for session ${sessionId} (${extraction.facts.length} facts, ${extraction.decisions.length} decisions)`);
  }

  eventBus.emit("distill:stage", { sessionId, nousId, stage: "verify", progress: 5, total: 6 });

  // Post-distillation verification — log warnings, don't block
  {
    const warnings: string[] = [];
    const postSession = store.findSessionById(sessionId);
    if (postSession) {
      if (postSession.tokenCountEstimate > 50_000) {
        warnings.push(`token estimate still high (${postSession.tokenCountEstimate})`);
      }
    }
    const postHistory = store.getHistory(sessionId, { excludeDistilled: true });
    const hasSummary = postHistory.some((m) => m.role === "assistant" && m.content.includes("Distillation #"));
    if (distillationNumber > 1 && !hasSummary) {
      warnings.push("summary message not found in undistilled history");
    }

    // Verify working state survived (primary sessions only)
    const ws = store.getWorkingState(sessionId);
    if (!ws && !opts.lightweight) {
      warnings.push("working state missing after distillation");
    }

    // Verify agent notes survived
    const notes = store.getNotes(sessionId);
    if (notes.length === 0 && !opts.lightweight) {
      warnings.push("all agent notes cleared during distillation");
    }

    // Verify compression ratio is meaningful
    if (result.tokensAfter > result.tokensBefore * 0.8) {
      warnings.push(`poor compression ratio: ${result.tokensBefore} → ${result.tokensAfter} (${Math.round((1 - result.tokensAfter / result.tokensBefore) * 100)}%)`);
    }

    if (warnings.length > 0) {
      for (const w of warnings) {
        log.warn(`Post-distillation: ${w}`);
      }
    } else {
      log.debug("Post-distillation verification passed");
    }
  }

  eventBus.emit("distill:after", { sessionId, nousId, distillationNumber, tokensBefore: result.tokensBefore, tokensAfter: result.tokensAfter, factsExtracted: result.factsExtracted, ...(opts.emergency ? { emergency: true } : {}) });

  log.info(
    `Distillation #${distillationNumber} complete: ${result.tokensBefore} → ${result.tokensAfter} tokens ` +
      `(${Math.round((1 - result.tokensAfter / result.tokensBefore) * 100)}% reduction)`,
  );

  return result;
}
